=== new probe spthy files ===
----- console/workspace/probes/round6/diff_asym.spthy -----
theory DiffAsym
begin

builtins: symmetric-encryption

// Diff theory whose two projected systems genuinely DIFFER, so one ordinary
// lemma is verified on one side and falsified on the other. Left branch of
// diff() outputs ~m in the clear (secrecy FALSE); right branch outputs it
// encrypted under a secret key (secrecy TRUE). Confirms the RHS/LHS projected
// verdicts are computed independently (not mirrored).
rule Send:
  [ Fr(~k), Fr(~m) ] --[ Sent(~m) ]-> [ Out(diff(~m, senc(~m, ~k))) ]

lemma secret:
  "All m #i. Sent(m) @ i ==> not (Ex #j. K(m) @ j)"

end
----- console/workspace/probes/round6/diff_false.spthy -----
theory DiffFalse
begin

builtins: symmetric-encryption

// Diff theory whose ordinary lemmas are FALSE on both projected systems, to
// capture the projected RHS/LHS *falsified* verdict phrases. Every prior diff
// capture only showed 'verified' projected lines, so the falsified projected
// forms (all-traces "falsified - found trace", exists-trace
// "falsified - no trace found") were unobserved until this probe.
rule Leak:
  [ Fr(~k), Fr(~m) ] --[ Sent(~m) ]-> [ Out(~m), Out(senc(diff(~m, ~m), ~k)) ]

// all-traces secrecy claim that is FALSE: ~m is Out() in the clear.
lemma leaked:
  "All m #i. Sent(m) @ i ==> not (Ex #j. K(m) @ j)"

// exists-trace claim that is UNSATISFIABLE: the same fresh m cannot be Sent
// twice, so no witnessing trace exists.
lemma impossible:
  exists-trace
  "Ex m #i #j. Sent(m) @ i & Sent(m) @ j & not(#i = #j)"

end
----- console/workspace/probes/round6/two_lemma.spthy -----
theory TwoLemma
begin

// A plain (non-diff) theory with two ordinary lemmas, to probe whether
// --lemma=<name> FILTERS the other lemma out of the summary entirely (a
// "skipped" terminal state = no summary line) versus listing it as
// analysis-incomplete.
rule A:
  [ Fr(~x) ] --[ P(~x) ]-> [ Out(~x) ]

lemma first:
  "All x #i. P(x) @ i ==> Ex #j. P(x) @ j"

lemma second:
  exists-trace
  "Ex x #i. P(x) @ i"

end

